INSERT INTO literature (literatureId, title, author, abstract, languageId, institutionId, publication_year, doi_url, open_access_url, reference) VALUES
('727cce4c-f100-4b98-a891-cd48ee0d9512', 'Scaffold: Quantum Programming Language', 'Abhari et al.', NULL, '6ec32296-2ab0-488a-a2ea-472a28bb272d', '8a9b1c2d-3e4f-5a6b-7c8d-9e1f2a3b4c5d', 2012, NULL, 'https://apps.dtic.mil/sti/tr/pdf/ADA571279.pdf', 'Abhari, Ali J., et al. "Scaffold: Quantum programming language." (2012).'),
('684f1eef-2ddf-49ac-a34a-81058cb7efc0', 'Quantum programming languages', 'Heim et al.', 'Quantum programming languages are essential to translate ideas into instructions that can be executed by a quantum computer. Not only are they crucial to the programming of quantum computers at scale but also they can facilitate the discovery and development of quantum algorithms even before hardware exists that is capable of executing them. Quantum programming languages are used for controlling existing physical devices, for estimating the execution costs of quantum algorithms on future devices, for teaching quantum computing concepts, or for verifying quantum algorithms and their implementations. They are used by newcomers and seasoned practitioners, researchers and developers working on the next ground-breaking discovery or applying known concepts to real-world problems. This variety in purpose and target audiences is reflected in the design and ecosystem of the existing quantum programming languages, depending on which factors a language prioritizes. In this Review, we highlight important aspects of quantum programming and how it differs from conventional programming. We overview a selection of several state-of-the-art quantum programming languages, highlight their salient features, and provide code samples for each of the languages and Docker files to facilitate installation of the software packages.', NULL, NULL, 2020, 'https://www.nature.com/articles/s42254-020-00245-7', NULL, 'Heim, Bettina, et al. "Quantum programming languages." Nature Reviews Physics 2.12 (2020): 709-722.'),
('581cccc9-9848-4c65-8a3a-5b150f93e7e2', 'Towards a Hierarchical Quantum Circuit Language', 'Schober and Wesley', 'Many circuit-based quantum programming languages contain limited functionality for handling programs  with quantum branching events. In this paper we introduce a hierarchical circuit language with two new  connectives, one for generalized controlled operations and one for sub-circuit exponentiation, to reason  formally about such programs. We construct the hierarchical circuit language using a novel category-theoretic  construction, demonstrate that its compositional properties are non-trivial, show a circuit identity which may  be useful for circuit optimization by a compiler, demonstrate how generalized controlled operations describe  quantum control flow, and then contrast generalized controlled operations with Pauli rotations.', NULL, '5d6e7f8a-9b1c-2d3e-4f5a-6b7c8d9e1f2a', 2025, NULL, 'https://cqi.inf.usi.ch/publications/Hierarchical_PlanQC2026.pdf', 'Heim, Bettina, et al. "Quantum programming languages." Nature Reviews Physics 2.12 (2020): 709-722.'),
('04fce93e-a641-476f-a050-3a4fa1d8455b', 'Alternation in Quantum Programming: From Superposition of Data to Superposition of Programs', 'Ying et al.', 'We extract a novel quantum programming paradigm - superposition of programs from the design idea of a popular class of quantum algorithms, namely quantum walkbased algorithms. The generality of this paradigm is guaranteed by the universality of quantum walks as a computational model. A new quantum programming language QGCL is then proposed to support the paradigm of superposition of programs. This language can be seen as a quantum extension of Dijkstra’s GCL (Guarded Command Language). Surprisingly, alternation in GCL splits into two different notions in the quantum setting: classical alternation (of quantum programs) and quantum alternation, with the latter being introduced in QGCL for the first time. Quantum alternation is the key program construct for realizing the paradigm of superposition of programs. The denotational semantics of QGCL are defined by introducing a new mathematical tool called the guarded composition of operator-valued functions. Then the weakest precondition semantics of QGCL can straightforwardly derived. Another very useful program construct in realizing the quantum programming paradigm of superposition of programs, called quantum choice, can be easily defined in terms of quantum alternation. The relation between quantum choices and probabilistic choices is clarified through defining the notion of local variables. We derive a family of algebraic laws for QGCL programs that can be used in program verification, transformations and compilation. The expressive power of QGCL is illustrated by several examples where various variants and generalizations of quantum walks are conveniently expressed using quantum alternation and quantum choice. We believe that quantum programming with quantum alternation and choice will play an important role in further exploiting the power of quantum computing.', NULL, '9c1d2e4f-6a3b-5c7d-8e9f-1a5c9d3e7f2a', 2014, NULL, 'https://arxiv.org/pdf/1402.5172', 'Ying, Mingsheng, Nengkun Yu, and Yuan Feng. "Alternation in quantum programming: from superposition of data to superposition of programs." arXiv preprint arXiv:1402.5172 (2014).'),
('c82b9022-de1c-4259-8db6-40704e600077', 'Logical Reversibility of Computation', 'Bennett', 'The usual general-purpose computing automaton (e.g.. a Turing machine) is logically irreversible- its transition function lacks a single-valued inverse. Here it is shown that such machines may he made logically reversible at every step, while retainillg their simplicity and their ability to do general computations. This result is of great physical interest because it makes plausible the existence of thermodynamically reversible computers which could perform useful computations at useful speed while dissipating considerably lessthan kT of energyper logical step. In the first stage of itscomputationthe logically reversibleautomatonparallels the corresponding irreversible automaton, except that it saves all intermediate results, thereby avoiding the irreversible operation of erasure. The second stage consistsof printing out the desired output. Thethird stage then reversibly disposes of all the undesired intermediate results by retracing the steps of the first stage in backward order (a process which is only possible because the first stage has been carried out reversibly), thereby restoring the machine (except for the now-written output tape) toits original condition. The final machine configuration thus contains the desired output anda reconstructed copy o f the input, but no other undesired data. The foregoing results are demonstrated explicitly using a type of three-tape Turing machine. The biosynthesis of messenger RNA is discussed as a physical example of reversible computation.', NULL, NULL, 1973, 'https://ieeexplore.ieee.org/document/5391327', NULL, 'C. H. Bennett, "Logical Reversibility of Computation," in IBM Journal of Research and Development, vol. 17, no. 6, pp. 525-532, Nov. 1973, doi: 10.1147/rd.176.0525.'),
('3679f1a7-ad3e-4651-b189-f758c663ef6b', 'Quantum theory, the Church-Turing principle and the universal quantum computer', 'Deutsch', 'The usual general-purpose computing automaton (e.g.. a Turing machine) is logically irreversible- its transition function lacks a single-valued inverse. Here it is shown that such machines may he made logically reversible at every step, while retainillg their simplicity and their ability to do general computations. This result is of great physical interest because it makes plausible the existence of thermodynamically reversible computers which could perform useful computations at useful speed while dissipating considerably lessthan kT of energyper logical step. In the first stage of itscomputationthe logically reversibleautomatonparallels the corresponding irreversible automaton, except that it saves all intermediate results, thereby avoiding the irreversible operation of erasure. The second stage consistsof printing out the desired output. Thethird stage then reversibly disposes of all the undesired intermediate results by retracing the steps of the first stage in backward order (a process which is only possible because the first stage has been carried out reversibly), thereby restoring the machine (except for the now-written output tape) toits original condition. The final machine configuration thus contains the desired output anda reconstructed copy o f the input, but no other undesired data. The foregoing results are demonstrated explicitly using a type of three-tape Turing machine. The biosynthesis of messenger RNA is discussed as a physical example of reversible computation.', NULL, 'f628076d-f0e7-4df0-83db-28c9779a8ecf', 1985, '10.1098/rspa.1985.0070', 'https://royalsocietypublishing.org/rspa/article/400/1818/97/15743/Quantum-theory-the-Church-Turing-principle-and-the', 'David Deutsch; Quantum theory, the Church–Turing principle and the universal quantum computer. Proc. A 1 July 1985; 400 (1818): 97–117. https://doi.org/10.1098/rspa.1985.0070'),
('aa258e6a-7e0b-4838-a522-57b4dd25019f', 'Quantum computational networks', 'Deutsch', 'The theory of quantum computational networks is the quantum generalization of the theory of logic circuits used in classical computing machines. Quantum gates are the generalization of classical logic gates. A single type of gate, the universal quantum gate, together with quantum ‘unit wires’, is adequate for constructing networks with any possible quantum computational property.', NULL, 'f628076d-f0e7-4df0-83db-28c9779a8ecf', 1989, 'https://doi.org/10.1098/rspa.1989.0099', NULL, 'David Elieser Deutsch; Quantum computational networks. Proc. A 1 September 1989; 425 (1868): 73–90. https://doi.org/10.1098/rspa.1989.0099'),
('43bc12e0-e81b-4727-9e3c-3e54586e40e8', 'Rapid solution of problems by quantum computation', 'Deutsch and Jozsa', 'A class of problems is described which can be solved more efficiently by quantum computation than by any classical or stochastic method. The quantum computation solves the problem with certainty in exponentially less time than any classical deterministic computation.', NULL, 'f628076d-f0e7-4df0-83db-28c9779a8ecf', 1992, 'https://doi.org/10.1098/rspa.1992.0167', NULL, 'David Deutsch, Richard Jozsa; Rapid solution of problems by quantum computation. Proc. A 1 December 1992; 439 (1907): 553–558. https://doi.org/10.1098/rspa.1992.0167'),
('63a11174-05fa-4de7-8614-af75a5466777', 'Quantum Complexity Theory', 'Bernstein and Vazirani', NULL, NULL, '2f9752c5-a746-4484-8ad6-9aa35d62a70a', 1993, NULL, 'https://dl.acm.org/doi/10.1145/167088.167097', "Ethan Bernstein and Umesh Vazirani. 1993. Quantum complexity theory. In Proceedings of the twenty-fifth annual ACM symposium on Theory of Computing (STOC '93). Association for Computing Machinery, New York, NY, USA, 11–20. https://doi.org/10.1145/167088.167097"),
-- ('8840c04e-54f8-4506-8801-474197e95837', 'Quantum measurements and the Abelian Stabilizer Problem', 'Kitaev', 'We present a polynomial quantum algorithm for the Abelian stabilizer problem which includes both factoring and the discrete logarithm. Thus we extend famous Shor’s results [7]. Our method is based on a procedure for measuring an eigenvalue of a unitary operator. Another application of this procedure is a polynomial quantum Fourier transform algorithm for an arbitrary finite Abelian group. The paper also contains a rather detailed introduction to the theory of quantum computation.', NULL, '2f9752c5-a746-4484-8ad6-9aa35d62a70a', 2024, NULL, 'http://arxiv.org/abs/quant-ph/9511026', "arXiv:quant-ph/9511026"),
('4d67cae0-7330-4eab-9552-19de65e2dcd7', 'A fast quantum mechanical algorithm for database search', 'Grover', NULL, NULL, NULL, 1996, NULL, 'https://dl.acm.org/doi/10.1145/237814.237866', "Lov K. Grover. 1996. A fast quantum mechanical algorithm for database search. In Proceedings of the twenty-eighth annual ACM symposium on Theory of Computing (STOC '96). Association for Computing Machinery, New York, NY, USA, 212–219. https://doi.org/10.1145/237814.237866"),
('8a1daded-199e-4b2e-bc74-40a6aa8f16cd', 'Extending the Lambda Calculus to Express Randomized and Quantumized Algorithms', 'Maymin', 'This paper introduces a formal metalanguage called the lambda-q calculus for the specification of quantum programming languages. This metalanguage is an extension of the lambda calculus, which provides a formal setting for the specification of classical programming languages. As an intermediary step, we introduce a formal metalanguage called the lambdap calculus for the specification of programming languages that allow true random number generation. We demonstrate how selected randomized algorithms can be programmed directly in the lambda-p calculus. We also demonstrate how satisfiability can be efficiently solved in the lambda-q calculus.', NULL, "d9b1c8e7-5f3a-4c9b-9e5e-2a1f0c8e4b2a", 1997, NULL, 'http://arxiv.org/abs/quant-ph/9612052', "arXiv:quant-ph/9612052"),
('5ffb7f3c-4438-48a1-a629-097b41088476', 'Polynomial-Time Algorithms for Prime Factorization and Discrete Logarithms on a Quantum Computer', 'Shor', 'A digital computer is generally believed to be an efficient universal computing device; that is, it is believed able to simulate any physical computing device with an increase in computation time by at most a polynomial factor. This may not be true when quantum mechanics is taken into consideration. This paper considers factoring integers and finding discrete logarithms, two problems which are generally thought to be hard on a classical computer and which have been used as the basis of several proposed cryptosystems. Efficient randomized algorithms are given for these two problems on a hypothetical quantum computer. These algorithms take a number of steps polynomial in the input size, e.g., the number of digits of the integer to be factored.', NULL, NULL, 1996, NULL, 'http://arxiv.org/abs/quant-ph/9508027', "arXiv:quant-ph/9508027"),
('ad1c1c2e-577f-4ccf-8bf2-f96af5d483ab', 'The Halting Problem for Quantum Computers', 'Linden', 'We argue that the halting problem for quantum computers which was first raised by Myers, is by no means solved, as has been claimed recently. We explicitly demonstrate the difficulties that arise in a quantum computer when different branches of the computation halt at different, unknown, times.', NULL, NULL, 1998, NULL, 'http://arxiv.org/abs/quant-ph/9806054', "arXiv:quant-ph/9806054"),
('279a19fc-331a-4c43-b09b-c38ca21cab0f', 'A Brief Survey Of Quantum Programming Languages', 'Sellinger', 'This article is a brief and subjective survey of quantum programming language research.', NULL, 'a342626c-b086-4ef3-b152-b10262cbfc64', 2004, 'https://link.springer.com/chapter/10.1007/978-3-540-24754-8_1', NULL, "Selinger, P. (2004). A Brief Survey of Quantum Programming Languages. In: Kameyama, Y., Stuckey, P.J. (eds) Functional and Logic Programming. FLOPS 2004. Lecture Notes in Computer Science, vol 2998. Springer, Berlin, Heidelberg. https://doi.org/10.1007/978-3-540-24754-8_1"),
('65234243-d172-4a91-8d03-31c12edf686a', 'A Lambda Calculus for Quantum Computation', 'Tonder', 'The classical lambda calculus may be regarded both as a programming language and as a formal algebraic system for reasoning about computation. It provides a computational model equivalent to the Turing machine, and continues to be of enormous benefit in the classical theory of computation. We propose that quantum computation, like its classical counterpart, may benefit from a version of the lambda calculus suitable for expressing and reasoning about quantum algorithms. In this paper we develop a quantum lambda calculus as an alternative model of quantum computation, which combines some of the benefits of both the quantum Turing machine and the quantum circuit models. The calculus turns out to be closely related to the linear lambda calculi used in the study of Linear Logic. We set up a computational model and an equational proof system for this calculus, and we argue that it is equivalent to the quantum Turing machine.', NULL, '6321c02a-e410-408c-bdde-6a005a964ec7', 2003, NULL, 'http://arxiv.org/abs/quant-ph/0307150', "arXiv:quant-ph/0307150"),
('8eab8ea9-494d-4619-bcc6-61ef51d49c73', 'A functional quantum programming language', 'Altenkirch and Grattage', 'We introduce the language QML, a functional language for quantum computations on finite types. Its design is guided by its categorical semantics: QML programs are interpreted by morphisms in the category FQC of finite quantum computations, which provides a constructive semantics of irreversible quantum computations realisable as quantum gates. QML integrates reversible and irreversible quantum computations in one language, using first order strict linear logic to make weakenings explicit. Strict programs are free from decoherence and hence preserve superpositions and entanglement – which is essential for quantum parallelism.', "e0c3f423-caba-4d9b-b440-fbf14e572d7d", '6d3c21ef-a02f-493e-9daf-7f5bf3e52e12', 2005, NULL, 'http://arxiv.org/abs/quant-ph/0409065', "arXiv:quant-ph/0409065"),
('0cbde824-f089-40da-a6aa-a73c5df7b381', 'Quantum programming languages: survey and bibliography', 'Gay', 'The field of quantum programming languages is developing rapidly and there is a surprisingly large literature. Research in this area includes the design of programming languages for quantum computing, the application of established semantic and logical techniques to the foundations of quantum mechanics, and the design of compilers for quantum programming languages. This article justifies the study of quantum programming languages, presents the basics of quantum computing, surveys the literature in quantum programming languages, and indicates directions for future research.', NULL, '6a693ab9-2148-4512-b593-2b4e6e92ec1a', 2006, "https://www.cambridge.org/core/journals/mathematical-structures-in-computer-science/article/abs/quantum-programming-languages-survey-and-bibliography/80E4ECC8AE770B625A48F2EE28358BA6", NULL, "GAY SJ. Quantum programming languages: survey and bibliography. Mathematical Structures in Computer Science. 2006;16(4):581-600. doi:10.1017/S0960129506005378"),
('3e69ea6b-332d-4f80-a353-47e523e66f17', 'Synthesis of Quantum Logic Circuits', 'Shende et al.', 'The pressure of fundamental limits on classical computation and the promise of exponential speedups from quantum effects have recently brought quantum circuits [10] to the attention of the Electronic Design Automation community [18, 28, 7, 27, 17]. We discuss efficient quantum logic circuits which perform two tasks: (i) implementing generic quantum computations and (ii) initializing quantum registers. In contrast to conventional computing, the latter task is nontrivial because the state-space of an n-qubit register is not finite and contains exponential superpositions of classical bit strings. Our proposed circuits are asymptotically optimal for respective tasks and improve earlier published results by at least a factor of two. The circuits for generic quantum computation constructed by our algorithms are the most efficient known today in terms of the number of difficult gates (quantum controlled-NOTs). They are based on an analogue of the Shannon decomposition of Boolean functions and a new circuit block, quantum multiplexor, that generalizes several known constructions. A theoretical lower bound implies that our circuits cannot be improved by more than a factor of two. We additionally show how to accommodate the severe architectural limitation of using only nearest-neighbor gates that is representative of current implementation technologies. This increases the number of gates by almost an order of magnitude, but preserves the asymptotic optimality of gate counts.', NULL, '81b18b87-6605-4d11-b926-6a02d87f50b6', 2006, NULL, 'https://arxiv.org/abs/quant-ph/0406176', "arXiv:quant-ph/0406176"),
('6d1b76c8-c026-4c49-9f05-a91dfd065d2c', 'Quantum Loop Programs', 'Ying and Feng.', 'Loop is a powerful program construct in classical computation, but its power is still not exploited fully in quantum computation. The exploitation of such power definitely requires a deep understanding of the mechanism of quantum loop programs. In this paper, we introduce a general scheme of quantum loops and describe its computational process. The notions of termination and almost termination are proposed for quantum loops, and the function computed by a quantum loop is defined. To show their expressive power, quantum loops are applied in describing quantum walks. Necessary and sufficient conditions for termination and almost termination of a general quantum loop on any mixed input state are presented. A quantum loop is said to be (almost) terminating if it (almost) terminates on any input state. We show that a quantum loop is almost terminating if and only if it is uniformly almost terminating. It is observed that a small disturbance either on the unitary transformation in the loop body or on the measurement in the loop guard can make any quantum loop (almost) terminating. Moreover, a representation of the function computed by a quantum loop is given in terms of finite summations of matrices. To illustrate the notions and results obtained in this paper, two simplest classes of quantum loop programs, one qubit quantum loops, and two qubit quantum loops defined by controlled gates, are carefully examined.', NULL, '5b3689cb-3746-4af2-9659-fc36fe0d4149', 2007, NULL, 'https://arxiv.org/abs/quant-ph/0605218', "arXiv:quant-ph/0605218"),
-- ('12480736-f25a-4163-80c1-9d7a2dffcf40', 'A reversible programming language and its invertible self-interpreter', 'Yokoyama and Glück.', 'A reversible programming language supports deterministic forward and backward computation. We formalize the programming language Janus and prove its reversibility. We provide a program inverter for the language and implement a self-interpreter that achieves deterministic forward and backward interpretation of Janus programs without using a computation history. As the selfinterpreter is implemented in a reversible language, it is invertible using local program inversion. Many physical phenomena are reversible and we demonstrate the power of Janus by implementing a reversible program for discrete simulation of the Schro ̈dinger wave equation that can be inverted as well as run forward and backward.', NULL, '5b3689cb-3746-4af2-9659-fc36fe0d4149', 2007, 'https://dl.acm.org/doi/10.1145/1244381.1244404', NULL, "Tetsuo Yokoyama and Robert Glück. 2007. A reversible programming language and its invertible self-interpreter. In Proceedings of the 2007 ACM SIGPLAN symposium on Partial evaluation and semantics-based program manipulation (PEPM '07). Association for Computing Machinery, New York, NY, USA, 144–153. https://doi.org/10.1145/1244381.1244404"),
('12480736-f25a-4163-80c1-9d7a2dffcf40', 'A Survey of Quantum Programming Languages: History, Methods, and Tools', 'Sofge', 'Quantum computer programming is emerging as a new subject domain from multidisciplinary research in quantum computing, computer science, mathematics (especially quantum logic, lambda calculi, and linear logic), and engineering attempts to build the first non-trivial quantum computer. This paper briefly surveys the history, methods, and proposed tools for programming quantum computers circa late 2007. It is intended to provide an extensive but non-exhaustive look at work leading up to the current state-of-the-art in quantum computer programming. Further, it is an attempt to analyze the needed programming tools for quantum programmers, to use this analysis to predict the direction in which the field is moving, and to make recommendations for further development of quantum programming language tools.', NULL, NULL, 2007, NULL, 'https://arxiv.org/abs/0804.1118', "arXiv:0804.1118"),
('8378435a-2cf0-43d3-b839-7ec6b7db5140', 'Principles of a reversible programming language', 'Yokoyama et al.', 'The principles of reversible programming languages are explicated and illustrated with reference to the design of a high-level imperative language, Janus. The fundamental properties for such languages include backward as well as forward determinism and reversible updates of data. The unique design features of the language include explicit post-condition assertions, direct access to an inverse semantics and the possibility of clean ({\ie}, garbage-free) computation of injective functions. We suggest the clean simulation of reversible Turing machines as a criterion for computing strength of reversible languages, and demonstrate this for Janus. We show the practicality of the language by implementation of a reversible fast Fourier transform. Our results indicate that the reversible programming paradigm has fundamental properties that are relevant to many different areas of computer science.', NULL, "cd22d006-6c09-4bc0-8926-780d52367b1b", 2008, NULL, 'https://dl.acm.org/doi/10.1145/1366230.1366239', "Tetsuo Yokoyama, Holger Bock Axelsen, and Robert Glück. 2008. Principles of a reversible programming language. In Proceedings of the 5th conference on Computing frontiers (CF '08). Association for Computing Machinery, New York, NY, USA, 43–54. https://doi.org/10.1145/1366230.1366239"),
('588f1770-b85d-46cd-b37f-8449884882ee', 'Quantum algorithm for linear systems of equations', 'Harrow et al.', 'Solving linear systems of equations is a common problem that arises both on its own and as a subroutine in more complex problems: given a matrix A and a vector ~b, find a vector ~x such that A~x = ~b. We consider the case where one doesn’t need to know the solution ~x itself, but rather an approximation of the expectation value of some operator associated with ~x, e.g., ~x†M~x for some matrix M . In this case, when A is sparse, N × N and has condition number κ, classical algorithms  can find ~x and estimate ~x†M~x in O ̃(N √κ) time. Here, we exhibit a quantum algorithm for this task that runs in poly(log N, κ) time, an exponential improvement over the best classical algorithm.', NULL, "cd22d006-6c09-4bc0-8926-780d52367b1b", 2009, 'https://journals.aps.org/prl/abstract/10.1103/PhysRevLett.103.150502', 'https://arxiv.org/abs/0811.3171', "arXiv:0811.3171"),
('46168e30-ba16-44b8-a56e-51f07129f534', 'Construction of a universal quantum computer', 'Lagana et al.', 'We construct a universal quantum computer following Deutsch’s original proposal of a universal quantum Turing machine UQTM . Like Deutsch’s UQTM, our machine can emulate any classical Turing machine and can execute any algorithm that can be implemented in the quantum gate array framework but under the control of a quantum program, and hence is universal. We present the architecture of the machine, which consists of a memory tape and a processor and describe the observables that comprise the registers of the processor and the instruction set, which includes a set of operations that can approximate any unitary operation to any desired accuracy and hence is quantum computationally universal. We present the unitary evolution operators that act on the machine to achieve universal computation and discuss each of them in detail and specify and discuss explicit program halting and concatenation schemes. We define and describe a set of primitive programs in order to demonstrate the universal nature of the machine. These primitive programs facilitate the implementation of more complex algorithms and we demonstrate their use by presenting a program that computes the NAND function, thereby also showing that the machine can compute any classically computable function.', NULL, NULL, 2009, 'https://journals.aps.org/pra/abstract/10.1103/PhysRevA.79.052322', NULL, NULL),
('7f3b9029-cf7b-4270-8b6d-fda102720cae', 'A Reversible Processor Architecture and Its Reversible Logic Design', 'Thomsen et al.', 'We describe the design of a purely reversible computing architecture, Bob, and its instruction set, BobISA. The special features of the design include a simple, yet expressive, locally-invertible instruction set, and fully reversible control logic and address calculation. We have designed an architecture with an ISA that is expressive enough to serve as the target for a compiler from a high-level structured reversible programming language. All-in-all, this paper demonstrates that the design of a complete reversible computing architecture is possible and can serve as the core of a programmable reversible computing system.', NULL, '29eb5feb-79d2-407c-b27b-41adc3d4185d', 2012, 'https://link.springer.com/chapter/10.1007/978-3-642-29517-1_3', NULL, 'Thomsen, M.K., Axelsen, H.B., Glück, R. (2012). A Reversible Processor Architecture and Its Reversible Logic Design. In: De Vos, A., Wille, R. (eds) Reversible Computation. RC 2011. Lecture Notes in Computer Science, vol 7165. Springer, Berlin, Heidelberg. https://doi.org/10.1007/978-3-642-29517-1_3'),
('9af1b00e-5a3d-4cad-81e0-537972d46dc3', 'Defining Quantum Control Flow', 'Ying et al.', 'A remarkable difference between quantum and classical programs is that the control flow of the former can be either classical or quantum. One of the key issues in the theory of quantum programming languages is defining and understanding quantum control flow. A functional language with quantum control flow was defined by Altenkirch and Grattage [Proc. LICS’05, pp. 249-258]. This paper extends their work, and we introduce a general quantum control structure by defining three new quantum program constructs, namely quantum guarded command, quantum choice and quantum recursion. We clarify the relation between quantum choices and probabilistic choices. An interesting difference between quantum recursions with classical control flows and with quantum control flows is revealed.', NULL, '9c1d2e4f-6a3b-5c7d-8e9f-1a5c9d3e7f2a', 2012, 'https://link.springer.com/chapter/10.1007/978-3-642-29517-1_3', 'https://arxiv.org/abs/1209.4379', 'arXiv:1209.4379');
